// Grafana alert payload 파싱 — title / status / 시간 범위 추출
const alert = $input.first().json;

// alertTitle: Grafana payload 구조의 다양한 자리에서 안전하게 추출
const alertTitle =
  alert.title
  || alert.commonLabels?.alertname
  || alert.groupLabels?.alertname
  || alert.alerts?.[0]?.labels?.alertname
  || alert.alerts?.[0]?.annotations?.summary
  || 'Unknown Alert';

// 분석 대상 시간 범위 — 현재 시각 기준 5분 전 ~ 현재
const now = new Date();
const fiveMinAgo = new Date(now.getTime() - 5 * 60 * 1000);

// Loki API는 nanosecond epoch 사용
const startNano = (fiveMinAgo.getTime() * 1_000_000).toString();
const endNano = (now.getTime() * 1_000_000).toString();

// KST(UTC+9) 포맷팅 — 표시용
function toKst(d) {
  const k = new Date(d.getTime() + 9 * 3600 * 1000);
  const Y = k.getUTCFullYear();
  const M = String(k.getUTCMonth() + 1).padStart(2, '0');
  const D = String(k.getUTCDate()).padStart(2, '0');
  const h = String(k.getUTCHours()).padStart(2, '0');
  const m = String(k.getUTCMinutes()).padStart(2, '0');
  return { date: `${Y}-${M}-${D}`, time: `${h}:${m}` };
}
const sK = toKst(fiveMinAgo);
const eK = toKst(now);
const timeRangeKst = sK.date === eK.date
  ? `${sK.date} ${sK.time} ~ ${eK.time} (KST)`
  : `${sK.date} ${sK.time} ~ ${eK.date} ${eK.time} (KST)`;

return [{
  json: {
    alertTitle,
    alertStatus: alert.status || 'firing',
    lokiQuery: '{service="backend", level="ERROR"}',
    startTime: startNano,
    endTime: endNano,
    timeRange: timeRangeKst
  }
}];

// Loki 응답에서 ERROR 로그 추출 → AI Agent용 system/user prompt 구성
const lokiResponse = $input.first().json;
const alertInfo = $('Parse Alert').first().json;

let logLines = [];

if (lokiResponse.data && lokiResponse.data.result) {
  for (const stream of lokiResponse.data.result) {
    if (stream.values) {
      for (const [timestamp, line] of stream.values) {
        logLines.push(line);
      }
    }
  }
}

// 토큰 비용 절감을 위해 길이 제한
const maxChars = 6000;
let errorLogs = logLines.join('\n---\n');
if (errorLogs.length > maxChars) {
  errorLogs = errorLogs.substring(0, maxChars) + '\n... (truncated)';
}

const systemPrompt = `당신은 Spring Boot 애플리케이션 장애 분석 전문가입니다.
에러 로그를 분석하여 아래 3가지 섹션으로 정리하세요. 각 섹션 헤더는 반드시 :mag: 이모지로 시작하세요.

출력 템플릿 (이 구조와 이모지를 그대로 따르세요):

:mag: *1. 에러 요약*
• 발생 시각: ...
• 에러 유형: ... (여러 종류면 각각 별도 bullet)
• 발생 위치: ...

:mag: *2. 원인 분석*
• 각 에러 유형별로 근본 원인 추정
• 관련 코드 위치/조건을 함께 언급

:mag: *3. 조치 방안*
• *즉시* — 지금 당장 할 수 있는 코드/설정 변경 (한 문장, 구체적으로)
• *단기* — 며칠~몇 주 안에 적용할 개선 (한 문장)
• *장기* — 구조/아키텍처 차원의 개선 (한 문장)

출력 형식 — Slack mrkdwn 규칙 (반드시 준수):
- 굵게는 *텍스트* (별표 1개). **텍스트**(별표 2개) 절대 사용 금지
- 기울임은 _텍스트_
- 인라인 코드는 \`코드\`
- 코드 블록은 삼중 백틱으로 감싸기 (꼭 필요할 때만)
- 헤더(#, ##, ###) 사용 금지
- 가로 구분선(---) 사용 금지
- 리스트는 • 으로 시작 (-, * 금지)
- 한국어로 작성, 위에 명시된 :mag: 외의 추가 이모지는 자제
- 간결하게`;

const userPrompt = `[Alert] ${alertInfo.alertTitle}
[Status] ${alertInfo.alertStatus}
[Time Range] ${alertInfo.timeRange}
[Error Count] ${logLines.length}건

--- 에러 로그 ---
${errorLogs}`;

return [{
  json: {
    systemPrompt,
    userPrompt,
    errorCount: logLines.length,
    alertInfo
  }
}];

// AI Agent 응답을 Slack mrkdwn 메시지로 변환
const aiOutput = $input.first().json;
const promptData = $('Build Prompt').first().json;

let analysis = aiOutput.output || aiOutput.text || JSON.stringify(aiOutput);

// Slack mrkdwn 호환 후처리 (모델이 표준 Markdown을 출력해도 안전하게 변환)
analysis = analysis
  .replace(/\*\*(.+?)\*\*/g, '*$1*')   // **bold** -> *bold*
  .replace(/^\s*#+\s+/gm, '')            // # / ## / ### 헤더 마커 제거
  .replace(/^\s*-{3,}\s*$/gm, '')        // --- 가로 구분선 제거
  .replace(/\n{3,}/g, '\n\n');           // 연속 빈 줄 정리

const alertInfo = promptData.alertInfo;
const errorCount = promptData.errorCount;

// 헤더 — 첫 줄 고정 + Time / Error Count만 표시
const text = `:rotating_light: *AI 에러 분석 리포트*\n\n` +
  `*Time:* ${alertInfo.timeRange}\n` +
  `*Error Count:* ${errorCount}건\n\n` +
  `${analysis}`;

return [{ json: { text } }];
